// src/pages/DetectPage.jsx
import Sidebar from '../components/Sidebar';
import startImage from '../assets/startpage.png';

function DetectPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 흐릿한 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-0 left-0 w-full h-full object-cover -z-10"
      />

      {/* 레이아웃: 사이드바 + 메인 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 메인 콘텐츠 */}
        <main className="flex-1 flex flex-col items-center justify-center min-h-[90vh] text-center px-4">
          <h1 className="text-2xl md:text-3xl font-bold text-gray-800 mb-4">
            AI에게 물어보세요!
          </h1>
          <p className="text-gray-600 mb-10">
            입력한 아파트의 전세가와 매매가를 비교하여<br />
            깡통 전세 여부를 예측합니다.
          </p>

          {/* 입력 박스 */}
          <div className="w-full max-w-xl flex items-center rounded-full shadow-md border border-blue-300 px-4 py-2 bg-white/80 backdrop-blur-sm">
            <input
              type="text"
              placeholder="예: 서울시 송파구 잠실동 123-4"
              className="flex-1 px-4 py-2 rounded-full outline-none bg-transparent"
            />
            <button className="text-blue-600 text-2xl pr-2 hover:text-blue-800">
              ➤
            </button>
          </div>
        </main>
      </div>
    </div>
  );
}

export default DetectPage;
